  'Pre-commitment devices (removing options) help enforce delayed gratification.': { prompt: 'Los dispositivos de precompromiso (eliminar opciones) ayudan a imponer la gratificación diferida.', options: ['Verdadero', 'Falso'], correctAnswer: 'Verdadero' },
