  'Notifications on your phone are designed to trigger dopamine hits.': { prompt: 'Las notificaciones en tu teléfono están diseñadas para desencadenar picos de dopamina.', options: ['Verdadero', 'Falso'], correctAnswer: 'Verdadero' },
