  'What does SMART stand for in goal setting?': { prompt: '¿Qué significa SMART en la definición de objetivos?', options: ['Simple, Medible, Alcanzable, Relevante, Temporal', 'Específico, Medible, Alcanzable, Relevante, Temporal', 'Estratégico, Motivador, Accionable, Realista, Rastreado', 'Pequeño, Significativo, Accesible, Fiable, Probado'], correctAnswer: 'Específico, Medible, Alcanzable, Relevante, Temporal' },
