  'What are OKRs?': { prompt: '¿Qué son los OKR?', options: ['Online Key Records', 'Objetivos y Resultados Clave', 'Organized Knowledge Reviews', 'Official Key Requirements'], correctAnswer: 'Objetivos y Resultados Clave' },
  'OKRs are used by companies like Google and Intel.': { prompt: 'Los OKR son usados por empresas como Google e Intel.', options: ['Verdadero', 'Falso'], correctAnswer: 'Verdadero' },
  'What is the difference between an objective and a key result?': { prompt: '¿Cuál es la diferencia entre un objetivo y un resultado clave?', options: ['Son lo mismo', 'Los objetivos son metas cualitativas; los resultados clave son hitos medibles', 'Los objetivos son números; los resultados clave son sentimientos', 'Los resultados clave vienen antes de los objetivos'], correctAnswer: 'Los objetivos son metas cualitativas; los resultados clave son hitos medibles' },
